import { describe, expect, test } from '@a0n/gnosis/test';
import {
  GNOSIS_RANDOMNESS_LEAN_MODULES,
  GNOSIS_RANDOMNESS_RUNTIME_STANCE,
  GNOSIS_SIMULATION_PRNG_DISCLAIMER,
  createLaceyNestedRng,
} from '../randomness';

describe('randomness core', () => {
  test('exposes stable Lean module anchors', () => {
    expect(GNOSIS_RANDOMNESS_LEAN_MODULES).toContain(
      'ForkRaceFoldTheorems.CryptographicPseudorandom',
    );
    expect(GNOSIS_RANDOMNESS_LEAN_MODULES).toContain(
      'ForkRaceFoldTheorems.ClinamenCryptoAntiBridge',
    );
    expect(GNOSIS_RANDOMNESS_LEAN_MODULES).toContain(
      'ForkRaceFoldTheorems.LandauerInformationPhysics',
    );
    expect(GNOSIS_RANDOMNESS_LEAN_MODULES).toContain(
      'ForkRaceFoldTheorems.BlackHoleInformationSketch',
    );
    expect(GNOSIS_RANDOMNESS_LEAN_MODULES.length).toBeGreaterThanOrEqual(11);
  });

  test('runtime stance is simulation-only', () => {
    expect(GNOSIS_RANDOMNESS_RUNTIME_STANCE).toBe('simulation_prng');
    expect(GNOSIS_SIMULATION_PRNG_DISCLAIMER.length).toBeGreaterThan(20);
  });

  test('nested PRNG factory is usable', () => {
    const rng = createLaceyNestedRng(0xfeedn);
    expect(rng.nextU64()).not.toBe(rng.nextU64());
  });
});
